sql:
SELECT location_id, COUNT(farmer_id) AS number_of_farmers
FROM farmers
GROUP BY location_id;

SELECT monitor_id, crop_id, record_id, crop_health_status
FROM crop_monitoring
WHERE monitor_date = '2020-01-01';

SELECT AVG(temperature_c_avg) AS avg_temperature
FROM environmental_conditions
WHERE year = 2020;

SELECT farmer_name
FROM farmers
WHERE location_id = (SELECT location_id FROM locations WHERE location_name = 'Farm 1');
